<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Snake</title>
  <style>
    :root {
      color-scheme: dark;
      --bg: #090d14;
      --panel: #111824;
      --panel-border: #263347;
      --text: #ecf5ff;
      --muted: #91a2b8;
      --green: #55e98d;
      --green-dark: #159b5a;
      --red: #ff526d;
    }

    * {
      box-sizing: border-box;
    }

    body {
      min-height: 100vh;
      margin: 0;
      display: grid;
      place-items: center;
      overflow: auto;
      background:
        radial-gradient(circle at 50% 20%, #192338 0, #0d131e 35%, var(--bg) 75%);
      color: var(--text);
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    }

    .game-shell {
      width: max-content;
      max-width: 100%;
      padding: 24px;
      text-align: center;
    }

    h1 {
      margin: 0 0 14px;
      color: var(--green);
      font-size: clamp(2rem, 5vw, 3.2rem);
      letter-spacing: 0.1em;
      text-transform: uppercase;
      text-shadow: 0 0 24px rgba(85, 233, 141, 0.28);
    }

    .info {
      width: 520px;
      max-width: calc(100vw - 32px);
      margin: 0 auto 10px;
      display: flex;
      align-items: center;
      justify-content: space-between;
      color: var(--muted);
      font-weight: 700;
    }

    #score {
      color: var(--text);
      font-size: 1.2rem;
    }

    #status {
      min-height: 1.4em;
    }

    .board-frame {
      display: inline-flex;
      padding: 10px;
      border: 1px solid var(--panel-border);
      border-radius: 16px;
      background: rgba(17, 24, 36, 0.9);
      box-shadow:
        0 24px 60px rgba(0, 0, 0, 0.45),
        0 0 0 1px rgba(255, 255, 255, 0.025) inset;
    }

    #snake {
      display: block;
      width: 520px;
      height: 520px;
      min-width: 400px;
      min-height: 400px;
      border-radius: 9px;
      background: #0b111a;
      image-rendering: auto;
      touch-action: none;
    }

    .controls {
      margin-top: 16px;
      display: flex;
      justify-content: center;
      gap: 10px;
      flex-wrap: wrap;
    }

    button {
      min-width: 100px;
      padding: 11px 18px;
      border: 1px solid #31415a;
      border-radius: 9px;
      background: linear-gradient(#1c2737, #131c29);
      color: var(--text);
      font: inherit;
      font-weight: 750;
      cursor: pointer;
      transition: transform 100ms ease, border-color 100ms ease, background 100ms ease;
    }

    button:hover {
      border-color: var(--green);
      background: linear-gradient(#213448, #172739);
    }

    button:active {
      transform: translateY(1px) scale(0.98);
    }

    button:focus-visible {
      outline: 3px solid rgba(85, 233, 141, 0.35);
      outline-offset: 2px;
    }

    #start {
      border-color: #248b57;
      background: linear-gradient(#177345, #105332);
    }

    .hint {
      margin: 13px 0 0;
      color: #71839a;
      font-size: 0.9rem;
    }
  </style>
</head>
<body>
  <main class="game-shell">
    <h1>Snake</h1>

    <div class="info">
      <div id="score" aria-live="polite">Score: 0</div>
      <div id="status" aria-live="polite">Ready</div>
    </div>

    <div class="board-frame">
      <canvas id="snake" width="600" height="600" aria-label="Snake game board"></canvas>
    </div>

    <div class="controls">
      <button id="start" type="button">Start</button>
      <button id="pause" type="button">Pause</button>
      <button id="reset" type="button">Reset</button>
    </div>

    <p class="hint">Use the arrow keys to steer</p>
  </main>

  <script>
    (() => {
      "use strict";

      const W = 20;
      const H = 20;
      const TICK_MS = 115;

      const canvas = document.getElementById("snake");
      const ctx = canvas.getContext("2d");
      const scoreElement = document.getElementById("score");
      const statusElement = document.getElementById("status");
      const startButton = document.getElementById("start");
      const pauseButton = document.getElementById("pause");
      const resetButton = document.getElementById("reset");

      const vectors = {
        up: [0, -1],
        down: [0, 1],
        left: [-1, 0],
        right: [1, 0]
      };

      const opposites = {
        up: "down",
        down: "up",
        left: "right",
        right: "left"
      };

      let body;
      let foodPosition;
      let direction;
      let queuedDirection;
      let isAlive;
      let points;
      let timer = null;
      let hasStarted = false;

      function updateScore() {
        scoreElement.textContent = `Score: ${points}`;
      }

      function cellIsOccupied(x, y) {
        return body.some(([bx, by]) => bx === x && by === y);
      }

      function placeRandomFood() {
        const freeCells = [];

        for (let y = 0; y < H; y++) {
          for (let x = 0; x < W; x++) {
            if (!cellIsOccupied(x, y)) {
              freeCells.push([x, y]);
            }
          }
        }

        if (freeCells.length === 0) {
          foodPosition = [-1, -1];
          return;
        }

        foodPosition = freeCells[Math.floor(Math.random() * freeCells.length)];
      }

      function roundedRect(x, y, width, height, radius) {
        const r = Math.min(radius, width / 2, height / 2);
        ctx.beginPath();
        ctx.moveTo(x + r, y);
        ctx.arcTo(x + width, y, x + width, y + height, r);
        ctx.arcTo(x + width, y + height, x, y + height, r);
        ctx.arcTo(x, y + height, x, y, r);
        ctx.arcTo(x, y, x + width, y, r);
        ctx.closePath();
      }

      function draw() {
        const cellW = canvas.width / W;
        const cellH = canvas.height / H;

        ctx.clearRect(0, 0, canvas.width, canvas.height);

        for (let y = 0; y < H; y++) {
          for (let x = 0; x < W; x++) {
            ctx.fillStyle = (x + y) % 2 === 0 ? "#0d151f" : "#101925";
            ctx.fillRect(x * cellW, y * cellH, cellW, cellH);
          }
        }

        if (foodPosition && foodPosition[0] >= 0) {
          const [fx, fy] = foodPosition;
          const cx = fx * cellW + cellW / 2;
          const cy = fy * cellH + cellH / 2;
          const radius = Math.min(cellW, cellH) * 0.31;

          ctx.save();
          ctx.shadowColor = "rgba(255, 66, 99, 0.9)";
          ctx.shadowBlur = 17;
          ctx.fillStyle = "#ff526d";
          ctx.beginPath();
          ctx.arc(cx, cy, radius, 0, Math.PI * 2);
          ctx.fill();

          ctx.shadowBlur = 0;
          ctx.fillStyle = "rgba(255,255,255,0.65)";
          ctx.beginPath();
          ctx.arc(cx - radius * 0.3, cy - radius * 0.3, radius * 0.22, 0, Math.PI * 2);
          ctx.fill();
          ctx.restore();
        }

        body.forEach(([x, y], index) => {
          const padding = index === 0 ? 2.5 : 3.5;
          const px = x * cellW + padding;
          const py = y * cellH + padding;
          const width = cellW - padding * 2;
          const height = cellH - padding * 2;

          ctx.save();
          if (index === 0) {
            ctx.shadowColor = "rgba(85, 233, 141, 0.55)";
            ctx.shadowBlur = 12;
            ctx.fillStyle = "#67f39b";
          } else {
            const lightness = Math.max(36, 53 - index * 0.65);
            ctx.fillStyle = `hsl(148 68% ${lightness}%)`;
          }

          roundedRect(px, py, width, height, Math.min(cellW, cellH) * 0.22);
          ctx.fill();
          ctx.restore();

          if (index === 0) {
            drawEyes(x, y, cellW, cellH);
          }
        });

        if (!isAlive) {
          ctx.save();
          ctx.fillStyle = "rgba(5, 8, 13, 0.66)";
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.fillStyle = "#ffffff";
          ctx.textAlign = "center";
          ctx.textBaseline = "middle";
          ctx.font = "800 48px system-ui, sans-serif";
          ctx.fillText("GAME OVER", canvas.width / 2, canvas.height / 2 - 18);
          ctx.fillStyle = "#a9b7c9";
          ctx.font = "600 21px system-ui, sans-serif";
          ctx.fillText("Press Reset or Start", canvas.width / 2, canvas.height / 2 + 34);
          ctx.restore();
        }
      }

      function drawEyes(x, y, cellW, cellH) {
        const activeDirection = direction;
        const centerX = x * cellW + cellW / 2;
        const centerY = y * cellH + cellH / 2;
        const spread = Math.min(cellW, cellH) * 0.16;
        const forward = Math.min(cellW, cellH) * 0.16;
        let eyes;

        if (activeDirection === "left" || activeDirection === "right") {
          const dx = activeDirection === "right" ? forward : -forward;
          eyes = [
            [centerX + dx, centerY - spread],
            [centerX + dx, centerY + spread]
          ];
        } else {
          const dy = activeDirection === "down" ? forward : -forward;
          eyes = [
            [centerX - spread, centerY + dy],
            [centerX + spread, centerY + dy]
          ];
        }

        ctx.fillStyle = "#06130c";
        for (const [ex, ey] of eyes) {
          ctx.beginPath();
          ctx.arc(ex, ey, Math.min(cellW, cellH) * 0.07, 0, Math.PI * 2);
          ctx.fill();
        }
      }

      function stopLoop() {
        if (timer !== null) {
          clearInterval(timer);
          timer = null;
        }
      }

      function resetGame() {
        body = [
          [10, 10],
          [9, 10],
          [8, 10],
          [7, 10]
        ];
        direction = "right";
        queuedDirection = "right";
        foodPosition = [4, 4];
        isAlive = true;
        points = 0;
        hasStarted = false;
        updateScore();
        statusElement.textContent = "Ready";
        draw();
      }

      function setDirection(next) {
        if (!Object.prototype.hasOwnProperty.call(vectors, next) || !isAlive) {
          return;
        }

        if (next === opposites[direction]) {
          return;
        }

        queuedDirection = next;
      }

      function tick() {
        if (!isAlive) {
          return;
        }

        if (queuedDirection !== opposites[direction]) {
          direction = queuedDirection;
        }

        const [dx, dy] = vectors[direction];
        const [headX, headY] = body[0];
        const newHead = [headX + dx, headY + dy];
        const [newX, newY] = newHead;

        const hitWall = newX < 0 || newX >= W || newY < 0 || newY >= H;
        const eating = newX === foodPosition[0] && newY === foodPosition[1];

        let hitSelf = false;
        const collisionLength = eating ? body.length : body.length - 1;

        for (let i = 0; i < collisionLength; i++) {
          if (body[i][0] === newX && body[i][1] === newY) {
            hitSelf = true;
            break;
          }
        }

        if (hitWall || hitSelf) {
          isAlive = false;
          stopLoop();
          statusElement.textContent = "Game over";
          draw();
          return;
        }

        body.unshift(newHead);

        if (eating) {
          points += 1;
          updateScore();
          placeRandomFood();
        } else {
          body.pop();
        }

        draw();
      }

      function startLoop() {
        if (!isAlive) {
          resetGame();
        }

        if (timer === null) {
          hasStarted = true;
          statusElement.textContent = "Running";
          timer = setInterval(tick, TICK_MS);
        }
      }

      function pauseLoop() {
        stopLoop();
        if (isAlive) {
          statusElement.textContent = hasStarted ? "Paused" : "Ready";
        }
      }

      function setFood(x, y) {
        const fx = Number(x);
        const fy = Number(y);

        if (
          Number.isInteger(fx) &&
          Number.isInteger(fy) &&
          fx >= 0 && fx < W &&
          fy >= 0 && fy < H
        ) {
          foodPosition = [fx, fy];
          draw();
        }
      }

      startButton.addEventListener("click", startLoop);
      pauseButton.addEventListener("click", pauseLoop);
      resetButton.addEventListener("click", () => {
        stopLoop();
        resetGame();
      });

      window.addEventListener("keydown", event => {
        const keyMap = {
          ArrowUp: "up",
          ArrowDown: "down",
          ArrowLeft: "left",
          ArrowRight: "right"
        };

        const next = keyMap[event.key];
        if (next) {
          event.preventDefault();
          setDirection(next);
        }

        if (event.code === "Space") {
          event.preventDefault();
          if (timer === null) {
            startLoop();
          } else {
            pauseLoop();
          }
        }
      }, { passive: false });

      window.game = {
        w: W,
        h: H,
        reset: resetGame,
        tick,
        setDir: setDirection,
        setFood,
        snake: () => body.map(segment => [...segment]),
        food: () => [...foodPosition],
        alive: () => isAlive,
        score: () => points
      };

      resetGame();
    })();
  </script>
</body>
</html>
